#include <iostream>
#include <vector>
#include <omp.h>

void scan(const int* input, int* output, int n) {
    std::vector<int> temp(n);
    temp[0] = 0;
    for (int i = 1; i < n; i++) {
        temp[i] = input[i - 1];
    }

    int step = 1;
    while (step < n) {
        #pragma omp parallel for
        for (int i = 0; i < n; i++) {
            if (i >= step)
                output[i] = temp[i] + temp[i - step];
            else
                output[i] = temp[i];
        }
        for (int i = 0; i < n; i++) {
            temp[i] = output[i];
        }
        step <<= 1;
    }
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> input(n);
    for (int i = 0; i < n; i++) {
        std::cin >> input[i];
    }
    std::vector<int> output(n);

    scan(input.data(), output.data(), n);

    for (int i = 0; i < n; i++) {
        std::cout << output[i] << std::endl;
    }
    return 0;
}
